(function() {
function fixImages() {
const imgs = document.querySelectorAll("img");
imgs.forEach(img => {
let real = img.getAttribute("data-original") || img.getAttribute("src");
        if (real && real.includes("/LoadImage.ashx")) {
            // 补全域名
            let url = real.startsWith("http") ? real : "https://www.tuao.cc" + real;

            // 强制替换
            img.src = url;
        }
    });
}
// 初始执行
fixImages();
// 监听动态加载
const observer = new MutationObserver(() => {
    fixImages();
});
observer.observe(document.body, {
    childList: true,
    subtree: true
});
})();

